import React, {type FunctionComponent} from 'react';
import {Flex} from "../../_compat";
import {type IMenuItem} from "@lmb-it/kitsconcerto-types";
import {type RouteObject, useRoutes} from "react-router-dom";
import {mapSectionsToRoutes} from "../Navigation/helper";

interface ILTRProps {
    routes: IMenuItem[];
}
const Routes = ({routes}:{routes:RouteObject[]})=>{
    return useRoutes(routes);
}



const AuthLayout = ({routes}:ILTRProps) => {
    const filteredRoutes = mapSectionsToRoutes(routes)
    return (
        <Flex w={'full'} h={'full'}>
            <Routes routes={filteredRoutes} />
        </Flex>
    );

};

export default AuthLayout;
